package com.example.hybridwebview

import android.Manifest
import android.content.ContentValues
import android.content.Context
import android.content.SharedPreferences
import android.content.pm.PackageManager
import android.graphics.Bitmap
import android.net.Uri
import android.os.Build
import android.os.Environment
import android.provider.MediaStore
import android.util.Base64
import android.util.Log
import android.webkit.JavascriptInterface
import android.webkit.WebView
import androidx.core.content.ContextCompat
import com.google.firebase.messaging.FirebaseMessaging
import org.json.JSONObject
import java.io.ByteArrayOutputStream
import java.io.File
import java.io.FileOutputStream
import java.text.SimpleDateFormat
import java.util.Date
import java.util.Locale

class NativeBridge(
    private val context: Context,
    private val webView: WebView,
    private val activityCallback: ActivityCallback
) {
    private val sharedPreferences: SharedPreferences =
        context.getSharedPreferences("hybrid_app_storage", Context.MODE_PRIVATE)

    companion object {
        const val BRIDGE_NAME = "NativeBridge"
        private const val TAG = "NativeBridge"
    }

    interface ActivityCallback {
        fun requestCameraPermission(callback: (Boolean) -> Unit)
        fun requestNotificationPermission(callback: (Boolean) -> Unit)
        fun openCamera(callback: (Uri?) -> Unit)
        fun openFileChooser(mimeType: String, callback: (Uri?) -> Unit)
        fun runOnMainThread(action: () -> Unit)
    }

    // ==================== Camera Functions ====================

    @JavascriptInterface
    fun openCamera(callbackName: String) {
        Log.d(TAG, "openCamera called with callback: $callbackName")
        activityCallback.requestCameraPermission { granted ->
            if (granted) {
                activityCallback.openCamera { uri ->
                    if (uri != null) {
                        val base64 = uriToBase64(uri)
                        executeCallback(callbackName, """{"success": true, "data": "$base64", "uri": "$uri"}""")
                    } else {
                        executeCallback(callbackName, """{"success": false, "error": "Camera cancelled"}""")
                    }
                }
            } else {
                executeCallback(callbackName, """{"success": false, "error": "Camera permission denied"}""")
            }
        }
    }

    @JavascriptInterface
    fun capturePhoto(callbackName: String) {
        openCamera(callbackName)
    }

    @JavascriptInterface
    fun isCameraAvailable(): Boolean {
        return context.packageManager.hasSystemFeature(PackageManager.FEATURE_CAMERA_ANY)
    }

    @JavascriptInterface
    fun hasCameraPermission(): Boolean {
        return ContextCompat.checkSelfPermission(
            context, Manifest.permission.CAMERA
        ) == PackageManager.PERMISSION_GRANTED
    }

    @JavascriptInterface
    fun requestCameraPermission(callbackName: String) {
        activityCallback.requestCameraPermission { granted ->
            executeCallback(callbackName, """{"granted": $granted}""")
        }
    }

    // ==================== Local Storage Functions ====================

    @JavascriptInterface
    fun setItem(key: String, value: String): Boolean {
        return try {
            sharedPreferences.edit().putString(key, value).apply()
            Log.d(TAG, "setItem: $key")
            true
        } catch (e: Exception) {
            Log.e(TAG, "setItem error", e)
            false
        }
    }

    @JavascriptInterface
    fun getItem(key: String): String? {
        return try {
            sharedPreferences.getString(key, null)
        } catch (e: Exception) {
            Log.e(TAG, "getItem error", e)
            null
        }
    }

    @JavascriptInterface
    fun removeItem(key: String): Boolean {
        return try {
            sharedPreferences.edit().remove(key).apply()
            true
        } catch (e: Exception) {
            Log.e(TAG, "removeItem error", e)
            false
        }
    }

    @JavascriptInterface
    fun clearStorage(): Boolean {
        return try {
            sharedPreferences.edit().clear().apply()
            true
        } catch (e: Exception) {
            Log.e(TAG, "clearStorage error", e)
            false
        }
    }

    @JavascriptInterface
    fun getAllKeys(): String {
        return try {
            val keys = sharedPreferences.all.keys
            val jsonArray = org.json.JSONArray(keys.toList())
            jsonArray.toString()
        } catch (e: Exception) {
            Log.e(TAG, "getAllKeys error", e)
            "[]"
        }
    }

    @JavascriptInterface
    fun setObject(key: String, jsonString: String): Boolean {
        return setItem(key, jsonString)
    }

    @JavascriptInterface
    fun getObject(key: String): String {
        return getItem(key) ?: "{}"
    }

    @JavascriptInterface
    fun getStorageSize(): Long {
        return try {
            val file = File(context.applicationInfo.dataDir, "shared_prefs/hybrid_app_storage.xml")
            if (file.exists()) file.length() else 0L
        } catch (e: Exception) {
            0L
        }
    }

    // ==================== Push Notification Functions ====================

    @JavascriptInterface
    fun requestNotificationPermission(callbackName: String) {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            activityCallback.requestNotificationPermission { granted ->
                executeCallback(callbackName, """{"granted": $granted}""")
            }
        } else {
            executeCallback(callbackName, """{"granted": true}""")
        }
    }

    @JavascriptInterface
    fun hasNotificationPermission(): Boolean {
        return if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            ContextCompat.checkSelfPermission(
                context, Manifest.permission.POST_NOTIFICATIONS
            ) == PackageManager.PERMISSION_GRANTED
        } else {
            true
        }
    }

    @JavascriptInterface
    fun getFCMToken(callbackName: String) {
        FirebaseMessaging.getInstance().token.addOnCompleteListener { task ->
            if (task.isSuccessful) {
                val token = task.result
                Log.d(TAG, "FCM Token: $token")
                setItem("fcm_token", token)
                executeCallback(callbackName, """{"success": true, "token": "$token"}""")
            } else {
                Log.e(TAG, "FCM token fetch failed", task.exception)
                executeCallback(
                    callbackName,
                    """{"success": false, "error": "${task.exception?.message ?: "Unknown error"}"}"""
                )
            }
        }
    }

    @JavascriptInterface
    fun subscribeTopic(topic: String, callbackName: String) {
        FirebaseMessaging.getInstance().subscribeToTopic(topic)
            .addOnCompleteListener { task ->
                if (task.isSuccessful) {
                    executeCallback(callbackName, """{"success": true, "topic": "$topic"}""")
                } else {
                    executeCallback(
                        callbackName,
                        """{"success": false, "error": "${task.exception?.message}"}"""
                    )
                }
            }
    }

    @JavascriptInterface
    fun unsubscribeTopic(topic: String, callbackName: String) {
        FirebaseMessaging.getInstance().unsubscribeFromTopic(topic)
            .addOnCompleteListener { task ->
                if (task.isSuccessful) {
                    executeCallback(callbackName, """{"success": true, "topic": "$topic"}""")
                } else {
                    executeCallback(
                        callbackName,
                        """{"success": false, "error": "${task.exception?.message}"}"""
                    )
                }
            }
    }

    @JavascriptInterface
    fun setNotificationBadge(count: Int) {
        // Store badge count for reference
        setItem("notification_badge_count", count.toString())
    }

    // ==================== Device Info Functions ====================

    @JavascriptInterface
    fun getDeviceInfo(): String {
        val info = JSONObject().apply {
            put("platform", "android")
            put("manufacturer", Build.MANUFACTURER)
            put("model", Build.MODEL)
            put("sdkVersion", Build.VERSION.SDK_INT)
            put("androidVersion", Build.VERSION.RELEASE)
            put("appVersion", getAppVersion())
            put("screenDensity", context.resources.displayMetrics.density)
            put("screenWidth", context.resources.displayMetrics.widthPixels)
            put("screenHeight", context.resources.displayMetrics.heightPixels)
        }
        return info.toString()
    }

    @JavascriptInterface
    fun getPlatform(): String = "android"

    @JavascriptInterface
    fun getAppVersion(): String {
        return try {
            val packageInfo = context.packageManager.getPackageInfo(context.packageName, 0)
            packageInfo.versionName ?: "unknown"
        } catch (e: Exception) {
            "unknown"
        }
    }

    // ==================== Utility Functions ====================

    @JavascriptInterface
    fun showToast(message: String) {
        activityCallback.runOnMainThread {
            android.widget.Toast.makeText(context, message, android.widget.Toast.LENGTH_SHORT).show()
        }
    }

    @JavascriptInterface
    fun showLongToast(message: String) {
        activityCallback.runOnMainThread {
            android.widget.Toast.makeText(context, message, android.widget.Toast.LENGTH_LONG).show()
        }
    }

    @JavascriptInterface
    fun log(tag: String, message: String) {
        Log.d(tag, message)
    }

    @JavascriptInterface
    fun shareText(title: String, text: String) {
        val intent = android.content.Intent(android.content.Intent.ACTION_SEND).apply {
            type = "text/plain"
            putExtra(android.content.Intent.EXTRA_SUBJECT, title)
            putExtra(android.content.Intent.EXTRA_TEXT, text)
        }
        val chooser = android.content.Intent.createChooser(intent, title)
        chooser.addFlags(android.content.Intent.FLAG_ACTIVITY_NEW_TASK)
        context.startActivity(chooser)
    }

    @JavascriptInterface
    fun copyToClipboard(text: String): Boolean {
        return try {
            val clipboard = context.getSystemService(Context.CLIPBOARD_SERVICE) as android.content.ClipboardManager
            val clip = android.content.ClipData.newPlainText("Copied Text", text)
            clipboard.setPrimaryClip(clip)
            true
        } catch (e: Exception) {
            false
        }
    }

    @JavascriptInterface
    fun vibrate(duration: Long) {
        try {
            val vibrator = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
                val vibratorManager =
                    context.getSystemService(Context.VIBRATOR_MANAGER_SERVICE) as android.os.VibratorManager
                vibratorManager.defaultVibrator
            } else {
                @Suppress("DEPRECATION")
                context.getSystemService(Context.VIBRATOR_SERVICE) as android.os.Vibrator
            }
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                vibrator.vibrate(
                    android.os.VibrationEffect.createOneShot(
                        duration,
                        android.os.VibrationEffect.DEFAULT_AMPLITUDE
                    )
                )
            } else {
                @Suppress("DEPRECATION")
                vibrator.vibrate(duration)
            }
        } catch (e: Exception) {
            Log.e(TAG, "Vibrate error", e)
        }
    }

    @JavascriptInterface
    fun openExternalUrl(url: String) {
        try {
            val intent = android.content.Intent(android.content.Intent.ACTION_VIEW, Uri.parse(url))
            intent.addFlags(android.content.Intent.FLAG_ACTIVITY_NEW_TASK)
            context.startActivity(intent)
        } catch (e: Exception) {
            Log.e(TAG, "openExternalUrl error", e)
        }
    }

    // ==================== Private Helper Functions ====================

    private fun executeCallback(callbackName: String, jsonData: String) {
        activityCallback.runOnMainThread {
            val script = "javascript:$callbackName($jsonData)"
            webView.evaluateJavascript(script, null)
        }
    }

    private fun uriToBase64(uri: Uri): String {
        return try {
            val inputStream = context.contentResolver.openInputStream(uri)
            val bytes = inputStream?.readBytes()
            inputStream?.close()
            if (bytes != null) {
                "data:image/jpeg;base64," + Base64.encodeToString(bytes, Base64.NO_WRAP)
            } else {
                ""
            }
        } catch (e: Exception) {
            Log.e(TAG, "uriToBase64 error", e)
            ""
        }
    }
}

