package com.example.hybridwebview

import android.Manifest
import android.annotation.SuppressLint
import android.app.Activity
import android.content.Intent
import android.content.pm.PackageManager
import android.graphics.Bitmap
import android.net.Uri
import android.os.Build
import android.os.Bundle
import android.os.Environment
import android.provider.MediaStore
import android.util.Log
import android.view.KeyEvent
import android.view.View
import android.view.ViewGroup
import android.webkit.*
import android.widget.FrameLayout
import android.widget.ProgressBar
import androidx.activity.result.ActivityResultLauncher
import androidx.activity.result.contract.ActivityResultContracts
import androidx.appcompat.app.AppCompatActivity
import androidx.core.content.ContextCompat
import androidx.core.content.FileProvider
import java.io.File
import java.text.SimpleDateFormat
import java.util.Date
import java.util.Locale

class MainActivity : AppCompatActivity(), NativeBridge.ActivityCallback {

    private lateinit var webView: WebView
    private lateinit var progressBar: ProgressBar
    private lateinit var container: FrameLayout

    private var cameraPermissionCallback: ((Boolean) -> Unit)? = null
    private var notificationPermissionCallback: ((Boolean) -> Unit)? = null
    private var cameraResultCallback: ((Uri?) -> Unit)? = null
    private var fileChooserCallback: ((Uri?) -> Unit)? = null
    private var currentPhotoUri: Uri? = null
    private var fileUploadCallback: ValueCallback<Array<Uri>>? = null

    companion object {
        private const val TAG = "MainActivity"
        // Change this to your web app URL
        private const val WEB_APP_URL = "https://your-webapp-url.com"
    }

    // Activity Result Launchers
    private lateinit var cameraPermissionLauncher: ActivityResultLauncher<String>
    private lateinit var notificationPermissionLauncher: ActivityResultLauncher<String>
    private lateinit var cameraLauncher: ActivityResultLauncher<Intent>
    private lateinit var fileChooserLauncher: ActivityResultLauncher<Intent>
    private lateinit var multiplePermissionsLauncher: ActivityResultLauncher<Array<String>>

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setupActivityResultLaunchers()
        setupUI()
        setupWebView()
        loadWebApp()
    }

    private fun setupActivityResultLaunchers() {
        cameraPermissionLauncher = registerForActivityResult(
            ActivityResultContracts.RequestPermission()
        ) { isGranted ->
            cameraPermissionCallback?.invoke(isGranted)
            cameraPermissionCallback = null
        }

        notificationPermissionLauncher = registerForActivityResult(
            ActivityResultContracts.RequestPermission()
        ) { isGranted ->
            notificationPermissionCallback?.invoke(isGranted)
            notificationPermissionCallback = null
        }

        cameraLauncher = registerForActivityResult(
            ActivityResultContracts.StartActivityForResult()
        ) { result ->
            if (result.resultCode == Activity.RESULT_OK) {
                cameraResultCallback?.invoke(currentPhotoUri)
            } else {
                cameraResultCallback?.invoke(null)
            }
            cameraResultCallback = null
        }

        fileChooserLauncher = registerForActivityResult(
            ActivityResultContracts.StartActivityForResult()
        ) { result ->
            if (result.resultCode == Activity.RESULT_OK) {
                val uri = result.data?.data
                fileChooserCallback?.invoke(uri)
                fileUploadCallback?.onReceiveValue(uri?.let { arrayOf(it) })
            } else {
                fileChooserCallback?.invoke(null)
                fileUploadCallback?.onReceiveValue(null)
            }
            fileChooserCallback = null
            fileUploadCallback = null
        }

        multiplePermissionsLauncher = registerForActivityResult(
            ActivityResultContracts.RequestMultiplePermissions()
        ) { permissions ->
            val allGranted = permissions.values.all { it }
            Log.d(TAG, "Multiple permissions result: $allGranted")
        }
    }

    private fun setupUI() {
        container = FrameLayout(this)

        webView = WebView(this).apply {
            layoutParams = FrameLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.MATCH_PARENT
            )
        }

        progressBar = ProgressBar(this, null, android.R.attr.progressBarStyleHorizontal).apply {
            layoutParams = FrameLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                8
            )
            max = 100
            isIndeterminate = false
        }

        container.addView(webView)
        container.addView(progressBar)
        setContentView(container)
    }

    @SuppressLint("SetJavaScriptEnabled")
    private fun setupWebView() {
        webView.settings.apply {
            javaScriptEnabled = true
            domStorageEnabled = true
            databaseEnabled = true
            allowFileAccess = true
            allowContentAccess = true
            javaScriptCanOpenWindowsAutomatically = true
            mediaPlaybackRequiresUserGesture = false
            mixedContentMode = WebSettings.MIXED_CONTENT_ALWAYS_ALLOW
            cacheMode = WebSettings.LOAD_DEFAULT
            setSupportZoom(true)
            builtInZoomControls = true
            displayZoomControls = false
            loadWithOverviewMode = true
            useWideViewPort = true

            // Enable modern web features
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                safeBrowsingEnabled = true
            }

            userAgentString = "$userAgentString HybridApp/1.0"
        }

        // Add JavaScript Bridge
        val nativeBridge = NativeBridge(this, webView, this)
        webView.addJavascriptInterface(nativeBridge, NativeBridge.BRIDGE_NAME)

        // WebView Client
        webView.webViewClient = object : WebViewClient() {
            override fun onPageStarted(view: WebView?, url: String?, favicon: Bitmap?) {
                super.onPageStarted(view, url, favicon)
                progressBar.visibility = View.VISIBLE
                Log.d(TAG, "Page started: $url")
            }

            override fun onPageFinished(view: WebView?, url: String?) {
                super.onPageFinished(view, url)
                progressBar.visibility = View.GONE
                injectBridgeHelpers()
                Log.d(TAG, "Page finished: $url")
            }

            override fun onReceivedError(
                view: WebView?,
                request: WebResourceRequest?,
                error: WebResourceError?
            ) {
                super.onReceivedError(view, request, error)
                if (request?.isForMainFrame == true) {
                    Log.e(TAG, "WebView error: ${error?.description}")
                    loadErrorPage()
                }
            }

            override fun shouldOverrideUrlLoading(
                view: WebView?,
                request: WebResourceRequest?
            ): Boolean {
                val url = request?.url?.toString() ?: return false

                // Handle external URLs
                return if (url.startsWith("http://") || url.startsWith("https://")) {
                    if (isInternalUrl(url)) {
                        false // Let WebView handle internal URLs
                    } else {
                        // Open external URLs in browser
                        val intent = Intent(Intent.ACTION_VIEW, Uri.parse(url))
                        startActivity(intent)
                        true
                    }
                } else {
                    // Handle custom schemes (tel:, mailto:, etc.)
                    try {
                        val intent = Intent(Intent.ACTION_VIEW, Uri.parse(url))
                        startActivity(intent)
                    } catch (e: Exception) {
                        Log.e(TAG, "Cannot handle URL: $url", e)
                    }
                    true
                }
            }
        }

        // WebChrome Client for file uploads and other features
        webView.webChromeClient = object : WebChromeClient() {
            override fun onProgressChanged(view: WebView?, newProgress: Int) {
                progressBar.progress = newProgress
            }

            override fun onShowFileChooser(
                webView: WebView?,
                filePathCallback: ValueCallback<Array<Uri>>?,
                fileChooserParams: FileChooserParams?
            ): Boolean {
                fileUploadCallback?.onReceiveValue(null)
                fileUploadCallback = filePathCallback

                val acceptTypes = fileChooserParams?.acceptTypes
                val isCamera = acceptTypes?.any { it.startsWith("image/") } == true

                if (isCamera) {
                    showImageSourceChooser()
                } else {
                    val intent = fileChooserParams?.createIntent()
                    if (intent != null) {
                        fileChooserLauncher.launch(intent)
                    }
                }
                return true
            }

            override fun onPermissionRequest(request: PermissionRequest?) {
                request?.let {
                    runOnUiThread {
                        it.grant(it.resources)
                    }
                }
            }

            override fun onGeolocationPermissionsShowPrompt(
                origin: String?,
                callback: GeolocationPermissions.Callback?
            ) {
                callback?.invoke(origin, true, false)
            }

            override fun onConsoleMessage(consoleMessage: ConsoleMessage?): Boolean {
                consoleMessage?.let {
                    Log.d("WebConsole", "${it.messageLevel()}: ${it.message()} -- ${it.sourceId()}:${it.lineNumber()}")
                }
                return true
            }
        }
    }

    private fun injectBridgeHelpers() {
        val jsHelpers = """
            (function() {
                if (window.NativeBridgeReady) return;
                
                window.NativeBridgeReady = true;
                
                // Promise-based wrappers for native bridge
                window.HybridBridge = {
                    // Camera
                    openCamera: function() {
                        return new Promise(function(resolve, reject) {
                            var callbackName = '_cameraCb_' + Date.now();
                            window[callbackName] = function(result) {
                                delete window[callbackName];
                                if (result.success) resolve(result);
                                else reject(result);
                            };
                            NativeBridge.openCamera(callbackName);
                        });
                    },
                    
                    isCameraAvailable: function() {
                        return NativeBridge.isCameraAvailable();
                    },
                    
                    hasCameraPermission: function() {
                        return NativeBridge.hasCameraPermission();
                    },
                    
                    requestCameraPermission: function() {
                        return new Promise(function(resolve) {
                            var callbackName = '_camPermCb_' + Date.now();
                            window[callbackName] = function(result) {
                                delete window[callbackName];
                                resolve(result.granted);
                            };
                            NativeBridge.requestCameraPermission(callbackName);
                        });
                    },
                    
                    // Local Storage
                    storage: {
                        set: function(key, value) {
                            if (typeof value === 'object') {
                                return NativeBridge.setItem(key, JSON.stringify(value));
                            }
                            return NativeBridge.setItem(key, String(value));
                        },
                        get: function(key) {
                            return NativeBridge.getItem(key);
                        },
                        getJSON: function(key) {
                            var val = NativeBridge.getItem(key);
                            try { return JSON.parse(val); }
                            catch(e) { return null; }
                        },
                        remove: function(key) {
                            return NativeBridge.removeItem(key);
                        },
                        clear: function() {
                            return NativeBridge.clearStorage();
                        },
                        keys: function() {
                            return JSON.parse(NativeBridge.getAllKeys());
                        }
                    },
                    
                    // Push Notifications
                    notifications: {
                        requestPermission: function() {
                            return new Promise(function(resolve) {
                                var callbackName = '_notifPermCb_' + Date.now();
                                window[callbackName] = function(result) {
                                    delete window[callbackName];
                                    resolve(result.granted);
                                };
                                NativeBridge.requestNotificationPermission(callbackName);
                            });
                        },
                        hasPermission: function() {
                            return NativeBridge.hasNotificationPermission();
                        },
                        getToken: function() {
                            return new Promise(function(resolve, reject) {
                                var callbackName = '_fcmTokenCb_' + Date.now();
                                window[callbackName] = function(result) {
                                    delete window[callbackName];
                                    if (result.success) resolve(result.token);
                                    else reject(result.error);
                                };
                                NativeBridge.getFCMToken(callbackName);
                            });
                        },
                        subscribe: function(topic) {
                            return new Promise(function(resolve, reject) {
                                var callbackName = '_subCb_' + Date.now();
                                window[callbackName] = function(result) {
                                    delete window[callbackName];
                                    if (result.success) resolve(result);
                                    else reject(result.error);
                                };
                                NativeBridge.subscribeTopic(topic, callbackName);
                            });
                        },
                        unsubscribe: function(topic) {
                            return new Promise(function(resolve, reject) {
                                var callbackName = '_unsubCb_' + Date.now();
                                window[callbackName] = function(result) {
                                    delete window[callbackName];
                                    if (result.success) resolve(result);
                                    else reject(result.error);
                                };
                                NativeBridge.unsubscribeTopic(topic, callbackName);
                            });
                        }
                    },
                    
                    // Utility
                    getDeviceInfo: function() {
                        return JSON.parse(NativeBridge.getDeviceInfo());
                    },
                    getPlatform: function() {
                        return NativeBridge.getPlatform();
                    },
                    showToast: function(msg) {
                        NativeBridge.showToast(msg);
                    },
                    share: function(title, text) {
                        NativeBridge.shareText(title, text);
                    },
                    copyToClipboard: function(text) {
                        return NativeBridge.copyToClipboard(text);
                    },
                    vibrate: function(duration) {
                        NativeBridge.vibrate(duration || 100);
                    },
                    openExternal: function(url) {
                        NativeBridge.openExternalUrl(url);
                    },
                    log: function(tag, msg) {
                        NativeBridge.log(tag, msg);
                    }
                };
                
                // Dispatch event to notify web app that bridge is ready
                var event = new CustomEvent('nativeBridgeReady', { detail: { platform: 'android' } });
                document.dispatchEvent(event);
                window.dispatchEvent(event);
                
                console.log('Native bridge initialized for Android');
            })();
        """.trimIndent()

        webView.evaluateJavascript(jsHelpers, null)
    }

    private fun showImageSourceChooser() {
        val hasCameraPermission = ContextCompat.checkSelfPermission(
            this, Manifest.permission.CAMERA
        ) == PackageManager.PERMISSION_GRANTED

        if (hasCameraPermission) {
            launchCameraForFileUpload()
        } else {
            cameraPermissionCallback = { granted ->
                if (granted) {
                    launchCameraForFileUpload()
                } else {
                    fileUploadCallback?.onReceiveValue(null)
                    fileUploadCallback = null
                }
            }
            cameraPermissionLauncher.launch(Manifest.permission.CAMERA)
        }
    }

    private fun launchCameraForFileUpload() {
        val photoUri = createImageFileUri()
        currentPhotoUri = photoUri
        if (photoUri != null) {
            val intent = Intent(MediaStore.ACTION_IMAGE_CAPTURE).apply {
                putExtra(MediaStore.EXTRA_OUTPUT, photoUri)
            }
            cameraResultCallback = { uri ->
                if (uri != null) {
                    fileUploadCallback?.onReceiveValue(arrayOf(uri))
                } else {
                    fileUploadCallback?.onReceiveValue(null)
                }
                fileUploadCallback = null
            }
            cameraLauncher.launch(intent)
        } else {
            fileUploadCallback?.onReceiveValue(null)
            fileUploadCallback = null
        }
    }

    private fun isInternalUrl(url: String): Boolean {
        val webAppHost = Uri.parse(WEB_APP_URL).host
        val urlHost = Uri.parse(url).host
        return urlHost == webAppHost || url.startsWith("file://") || url.startsWith("data:")
    }

    private fun loadWebApp() {
        webView.loadUrl(WEB_APP_URL)
    }

    private fun loadErrorPage() {
        val errorHtml = """
            <!DOCTYPE html>
            <html>
            <head>
                <meta name="viewport" content="width=device-width, initial-scale=1.0">
                <style>
                    body { 
                        font-family: -apple-system, BlinkMacSystemFont, sans-serif;
                        display: flex; align-items: center; justify-content: center;
                        min-height: 100vh; margin: 0; background: #f5f5f5;
                        text-align: center; padding: 20px; box-sizing: border-box;
                    }
                    .container { max-width: 400px; }
                    h1 { color: #333; font-size: 24px; }
                    p { color: #666; font-size: 16px; line-height: 1.5; }
                    button { 
                        background: #2196F3; color: white; border: none;
                        padding: 12px 32px; border-radius: 8px; font-size: 16px;
                        cursor: pointer; margin-top: 20px;
                    }
                    button:active { background: #1976D2; }
                </style>
            </head>
            <body>
                <div class="container">
                    <h1>Connection Error</h1>
                    <p>Unable to load the application. Please check your internet connection and try again.</p>
                    <button onclick="window.location.reload()">Retry</button>
                </div>
            </body>
            </html>
        """.trimIndent()
        webView.loadDataWithBaseURL(null, errorHtml, "text/html", "UTF-8", null)
    }

    private fun createImageFileUri(): Uri? {
        return try {
            val timeStamp = SimpleDateFormat("yyyyMMdd_HHmmss", Locale.getDefault()).format(Date())
            val imageFileName = "JPEG_${timeStamp}_"
            val storageDir = getExternalFilesDir(Environment.DIRECTORY_PICTURES)
            val imageFile = File.createTempFile(imageFileName, ".jpg", storageDir)
            FileProvider.getUriForFile(
                this,
                "${applicationContext.packageName}.fileprovider",
                imageFile
            )
        } catch (e: Exception) {
            Log.e(TAG, "Error creating image file", e)
            null
        }
    }

    // ==================== NativeBridge.ActivityCallback Implementation ====================

    override fun requestCameraPermission(callback: (Boolean) -> Unit) {
        if (ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA)
            == PackageManager.PERMISSION_GRANTED
        ) {
            callback(true)
        } else {
            cameraPermissionCallback = callback
            cameraPermissionLauncher.launch(Manifest.permission.CAMERA)
        }
    }

    override fun requestNotificationPermission(callback: (Boolean) -> Unit) {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            if (ContextCompat.checkSelfPermission(this, Manifest.permission.POST_NOTIFICATIONS)
                == PackageManager.PERMISSION_GRANTED
            ) {
                callback(true)
            } else {
                notificationPermissionCallback = callback
                notificationPermissionLauncher.launch(Manifest.permission.POST_NOTIFICATIONS)
            }
        } else {
            callback(true)
        }
    }

    override fun openCamera(callback: (Uri?) -> Unit) {
        val photoUri = createImageFileUri()
        currentPhotoUri = photoUri
        if (photoUri != null) {
            cameraResultCallback = callback
            val intent = Intent(MediaStore.ACTION_IMAGE_CAPTURE).apply {
                putExtra(MediaStore.EXTRA_OUTPUT, photoUri)
            }
            cameraLauncher.launch(intent)
        } else {
            callback(null)
        }
    }

    override fun openFileChooser(mimeType: String, callback: (Uri?) -> Unit) {
        fileChooserCallback = callback
        val intent = Intent(Intent.ACTION_GET_CONTENT).apply {
            type = mimeType
            addCategory(Intent.CATEGORY_OPENABLE)
        }
        fileChooserLauncher.launch(intent)
    }

    override fun runOnMainThread(action: () -> Unit) {
        runOnUiThread(action)
    }

    // ==================== Lifecycle & Navigation ====================

    override fun onKeyDown(keyCode: Int, event: KeyEvent?): Boolean {
        if (keyCode == KeyEvent.KEYCODE_BACK && webView.canGoBack()) {
            webView.goBack()
            return true
        }
        return super.onKeyDown(keyCode, event)
    }

    override fun onResume() {
        super.onResume()
        webView.onResume()
        // Notify web app that it's in foreground
        webView.evaluateJavascript(
            "if(window.onNativeResume) window.onNativeResume();",
            null
        )
    }

    override fun onPause() {
        super.onPause()
        webView.onPause()
        // Notify web app that it's in background
        webView.evaluateJavascript(
            "if(window.onNativePause) window.onNativePause();",
            null
        )
    }

    override fun onDestroy() {
        webView.destroy()
        super.onDestroy()
    }

    // Handle push notification intent
    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        intent?.extras?.let { extras ->
            val notificationData = extras.keySet().associate { key ->
                key to (extras.getString(key) ?: "")
            }
            val jsonData = org.json.JSONObject(notificationData).toString()
            webView.evaluateJavascript(
                "if(window.onNotificationTapped) window.onNotificationTapped($jsonData);",
                null
            )
        }
    }
}

// ==================== PushNotificationService.kt ====================
package com.example.hybridwebview

import android.app.NotificationManager
import android.app.PendingIntent
import android.content.Context
import android.content.Intent
import android.os.Build
import android.util.Log
import androidx.core.app.NotificationCompat
import com.google.firebase.messaging.FirebaseMessagingService
import com.google.firebase.messaging.RemoteMessage

class PushNotificationService : FirebaseMessagingService() {

    companion object {
        private const val TAG = "PushNotificationService"
    }

    override fun onNewToken(token: String) {
        super.onNewToken(token)
        Log.d(TAG, "New FCM token: $token")

        // Store token locally
        val prefs = getSharedPreferences("hybrid_app_storage", Context.MODE_PRIVATE)
        prefs.edit().putString("fcm_token", token).apply()

        // You can also send the token to your server here
    }

    override fun onMessageReceived(message: RemoteMessage) {
        super.onMessageReceived(message)
        Log.d(TAG, "Message received from: ${message.from}")

        val title = message.notification?.title ?: message.data["title"] ?: "Notification"
        val body = message.notification?.body ?: message.data["body"] ?: ""
        val data = message.data

        showNotification(title, body, data)
    }

    private fun showNotification(title: String, body: String, data: Map<String, String>) {
        val intent = Intent(this, MainActivity::class.java).apply {
            flags = Intent.FLAG_ACTIVITY_CLEAR_TOP or Intent.FLAG_ACTIVITY_SINGLE_TOP
            data.forEach { (key, value) ->
                putExtra(key, value)
            }
        }

        val pendingIntentFlags = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
            PendingIntent.FLAG_IMMUTABLE or PendingIntent.FLAG_UPDATE_CURRENT
        } else {
            PendingIntent.FLAG_UPDATE_CURRENT
        }

        val pendingIntent = PendingIntent.getActivity(
            this,
            System.currentTimeMillis().toInt(),
            intent,
            pendingIntentFlags
        )

        val notification = NotificationCompat.Builder(this, HybridApplication.NOTIFICATION_CHANNEL_ID)
            .setSmallIcon(android.R.drawable.ic_dialog_info) // Replace with your app icon
            .setContentTitle(title)
            .setContentText(body)
            .setAutoCancel(true)
            .setPriority(NotificationCompat.PRIORITY_HIGH)
            .setContentIntent(pendingIntent)
            .setStyle(NotificationCompat.BigTextStyle().bigText(body))
            .build()

        val notificationManager = getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
        notificationManager.notify(System.currentTimeMillis().toInt(), notification)
    }
}